This treemap uses Observable JS to render a D3 hierarchy. It features centered labels, a hover effect, and a custom HTML floating tooltip.

data = ({
  name: "root",
  children: [
    { 
      name: "Frontend", 
      children: [
        {name: "React", value: 100}, 
        {name: "Vue", value: 60}, 
        {name: "Svelte", value: 40}
      ] 
    },
    { 
      name: "Backend", 
      children: [
        {name: "Node.js", value: 80}, 
        {name: "Python", value: 90}, 
        {name: "Go", value: 50}
      ] 
    },
    { 
      name: "DevOps", 
      children: [
        {name: "Docker", value: 70}, 
        {name: "K8s", value: 110}
      ] 
    }
  ]
})

width = 800
height = 500
fontSize = "24px" // &lt;--- ADJUST FONT SIZE HERE

// --- 2. HIERARCHY CALCULATION ---
root = {
  const h = d3.hierarchy(data)
      .sum(d =&gt; d.value)
      .sort((a, b) =&gt; b.value - a.value);

  return d3.treemap()
      .size([width, height])
      .paddingInner(2)
      (h);
}

// --- 3. TOOLTIP ELEMENT ---
// We create a hidden div in the HTML body to act as the tooltip
tooltip = d3.select("body").append("div")
    .style("position", "absolute")
    .style("visibility", "hidden")
    .style("background", "rgba(0, 0, 0, 0.8)")
    .style("color", "#fff")
    .style("padding", "8px")
    .style("border-radius", "4px")
    .style("font-size", "12px")
    .style("pointer-events", "none")
    .style("z-index", "1000")
    .style("font-family", "sans-serif");

// --- 4. CHART RENDERING ---
chart = {
  const svg = d3.create("svg")
      .attr("viewBox", [0, 0, width, height])
      .attr("width", "100%")
      .attr("height", "auto")
      .style("font", "12px sans-serif");

  const leaf = svg.selectAll("g")
    .data(root.leaves())
    .join("g")
    .attr("transform", d =&gt; `translate(${d.x0},${d.y0})`);

  // Draw Rectangles
  leaf.append("rect")
    .attr("fill", d =&gt; { 
        let p = d; while (p.depth &gt; 1) p = p.parent; 
        return d3.schemeTableau10[data.children.indexOf(p.data) % 10]; 
    })
    .attr("fill-opacity", 0.7)
    .attr("width", d =&gt; d.x1 - d.x0)
    .attr("height", d =&gt; d.y1 - d.y0)
    .attr("stroke", "white")
    .on("mouseover", function(event, d) {
      d3.select(this).attr("fill-opacity", 1);
      tooltip.style("visibility", "visible")
             .html(`&lt;strong&gt;${d.data.name}&lt;/strong&gt;&lt;br/&gt;Value: ${d.value}`);
    })
    .on("mousemove", function(event) {
      tooltip.style("top", (event.pageY - 10) + "px")
             .style("left", (event.pageX + 10) + "px");
    })
    .on("mouseout", function() {
      d3.select(this).attr("fill-opacity", 0.7);
      tooltip.style("visibility", "hidden");
    });

  // Draw Centered Labels
  leaf.append("text")
    .attr("x", d =&gt; (d.x1 - d.x0) / 2)
    .attr("y", d =&gt; (d.y1 - d.y0) / 2)
    .attr("dy", "0.35em")
    .attr("text-anchor", "middle")
    .attr("fill", "white")
    .style("font-size", fontSize) // &lt;--- APPLYING FONT SIZE
    .style("font-weight", "bold") // &lt;--- ADDED FONT WEIGHT
    .style("pointer-events", "none") // Ensures hover events pass through to the rect
    .text(d =&gt; (d.x1 - d.x0 &gt; 40 && d.y1 - d.y0 &gt; 20) ? d.data.name : "");

  return svg.node();
}

